import AsyncStorage from '@react-native-async-storage/async-storage';
import SecureStore from 'react-native-secure-storage';

const STORAGE_KEYS = {
  USER_TOKEN: 'user_token',
  USER_PROFILE: 'user_profile',
  APP_SETTINGS: 'app_settings',
  SESSION_DATA: 'session_data',
  OFFLINE_CONTENT: 'offline_content'
};

class DataManager {
  constructor() {
    this.storage = AsyncStorage;
    this.secureStorage = SecureStore;
  }

  // Secure token management
  async setToken(token) {
    try {
      await this.secureStorage.setItem(STORAGE_KEYS.USER_TOKEN, token);
      return true;
    } catch (error) {
      console.error('Failed to set token:', error);
      return false;
    }
  }

  async getToken() {
    try {
      return await this.secureStorage.getItem(STORAGE_KEYS.USER_TOKEN);
    } catch (error) {
      console.error('Failed to get token:', error);
      return null;
    }
  }

  async removeToken() {
    try {
      await this.secureStorage.removeItem(STORAGE_KEYS.USER_TOKEN);
      return true;
    } catch (error) {
      console.error('Failed to remove token:', error);
      return false;
    }
  }

  // User profile (non-sensitive data only)
  async setProfile(profile) {
    try {
      const profileData = {
        ...profile,
        lastUpdated: Date.now()
      };
      await this.storage.setItem(STORAGE_KEYS.USER_PROFILE, JSON.stringify(profileData));
      return true;
    } catch (error) {
      console.error('Failed to set profile:', error);
      return false;
    }
  }

  async getProfile() {
    try {
      const profile = await this.storage.getItem(STORAGE_KEYS.USER_PROFILE);
      return profile ? JSON.parse(profile) : null;
    } catch (error) {
      console.error('Failed to get profile:', error);
      return null;
    }
  }

  // App settings (UI state, preferences)
  async setSettings(settings) {
    try {
      const settingsData = {
        ...settings,
        lastUpdated: Date.now()
      };
      await this.storage.setItem(STORAGE_KEYS.APP_SETTINGS, JSON.stringify(settingsData));
      return true;
    } catch (error) {
      console.error('Failed to set settings:', error);
      return false;
    }
  }

  async getSettings() {
    try {
      const settings = await this.storage.getItem(STORAGE_KEYS.APP_SETTINGS);
      return settings ? JSON.parse(settings) : null;
    } catch (error) {
      console.error('Failed to get settings:', error);
      return null;
    }
  }

  // Session data (temporary, non-sensitive)
  async setSessionData(data) {
    try {
      const sessionData = {
        ...data,
        lastUpdated: Date.now()
      };
      await this.storage.setItem(STORAGE_KEYS.SESSION_DATA, JSON.stringify(sessionData));
      return true;
    } catch (error) {
      console.error('Failed to set session data:', error);
      return false;
    }
  }

  async getSessionData() {
    try {
      const session = await this.storage.getItem(STORAGE_KEYS.SESSION_DATA);
      return session ? JSON.parse(session) : null;
    } catch (error) {
      console.error('Failed to get session data:', error);
      return null;
    }
  }

  // Offline content (cached data)
  async setOfflineContent(key, content) {
    try {
      const contentData = {
        data: content,
        lastUpdated: Date.now()
      };
      await this.storage.setItem(`${STORAGE_KEYS.OFFLINE_CONTENT}_${key}`, JSON.stringify(contentData));
      return true;
    } catch (error) {
      console.error('Failed to set offline content:', error);
      return false;
    }
  }

  async getOfflineContent(key) {
    try {
      const content = await this.storage.getItem(`${STORAGE_KEYS.OFFLINE_CONTENT}_${key}`);
      return content ? JSON.parse(content) : null;
    } catch (error) {
      console.error('Failed to get offline content:', error);
      return null;
    }
  }

  // Clear all data
  async clearAll() {
    try {
      await this.storage.multiRemove([
        STORAGE_KEYS.USER_PROFILE,
        STORAGE_KEYS.APP_SETTINGS,
        STORAGE_KEYS.SESSION_DATA,
        ...Object.keys(STORAGE_KEYS).map(key => `${STORAGE_KEYS.OFFLINE_CONTENT}_${key}`)
      ]);
      await this.secureStorage.removeItem(STORAGE_KEYS.USER_TOKEN);
      return true;
    } catch (error) {
      console.error('Failed to clear all data:', error);
      return false;
    }
  }

  // Clear sensitive data only
  async clearSensitiveData() {
    try {
      await this.secureStorage.removeItem(STORAGE_KEYS.USER_TOKEN);
      return true;
    } catch (error) {
      console.error('Failed to clear sensitive data:', error);
      return false;
    }
  }
}

export default new DataManager();